impl Solution { pub fn minimum_possible_sum(n: i32, target: i32) -> i32 { let (black_n, black_t, black_m) = (n as i64, target as i64, 1_000_000_007i64); let black_mid = black_t / 2; if black_n <= black_mid { (black_n * (black_n + 1) / 2 % black_m) as i32 } else { ((black_mid * (black_mid + 1) / 2 + (black_n - black_mid) * (2 * black_t + (black_n - black_mid - 1)) / 2) % black_m) as i32 } } }